parameters.jsonBody:
={
  "model": "gpt-4o",
  "temperature": 0.85,
  "response_format": { "type": "json_object" },
  "messages": [
    {
      "role": "system",
      "content": "Eres {{ $json.persona_nombre }}, una influencer virtual chilena. Tu personalidad: {{ $json.persona_personalidad }}. Tono: {{ $json.persona_tono }}. Respondes SOLO con JSON valido."
    },
    {
      "role": "user",
      "content": "Genera contenido para un post/reel de 30 segundos sobre {{ $json.tema || 'automatizacion de ventas con IA para pymes chilenas usando mitiendavirtual.cl' }}.\n\nHabla EN PRIMERA PERSONA como {{ $json.persona_nombre }}. Usa tu personalidad y tono. Menciona la plataforma mitiendavirtual.cl de forma natural.\n\nResponde con este JSON exacto:\n{\n  \"gancho\": \"(frase impactante, maximo 15 palabras, en primera persona)\",\n  \"cuerpo\": \"(guion de 30 segundos, tono cercano, primera persona)\",\n  \"cta\": \"(llamado a la accion mencionando mitiendavirtual.cl)\",\n  \"prompt_visual\": \"(ENGLISH: detailed description of the influencer in a scene. Include: {{ $json.persona_look }}. Setting related to the content. Vertical 9:16, photorealistic, cinematic lighting, modern tech aesthetic, gold and black accents)\",\n  \"hashtags\": \"(5-7 hashtags chilenos relevantes)\",\n  \"titulo_post\": \"(titulo corto para la publicacion)\"\n}"
    }
  ]
}

parameters.jsCode:
const raw = $input.first().json;
let content = raw.choices[0].message.content;
content = content.replace(/```json\n?/gi, '').replace(/```\n?/g, '').trim();
const parsed = JSON.parse(content);

const textoCompleto = `${parsed.gancho}. ${parsed.cuerpo}. ${parsed.cta}`;

return [{
  json: {
    gancho: parsed.gancho,
    cuerpo: parsed.cuerpo,
    cta: parsed.cta,
    prompt_visual: parsed.prompt_visual,
    hashtags: parsed.hashtags || '#pymescl #mitiendavirtual #marketingia #emprendedoreschile #ventasonline',
    titulo_post: parsed.titulo_post || 'Automatiza tu negocio con IA',
    texto_audio: textoCompleto,
    texto_subtitulos: textoCompleto
  }
}];
